"""
Simple script to automate custom building for my
personal website
"""

import os
import random
import argparse

RESUME_TYPES = ["short", "long"]


def _build_resume(resume_type="short"):
    """
    Builds the requested resume version using pdflatex

    :param resume_type: (str) Type of resume. Can only be from the
                        RESUMETYPES list
    """

    # consistency checks
    if resume_type not in RESUME_TYPES:
        print("Invalid resume type %s.Skipping build" % resume_type)
        exit()

    resume_content_tex_fn = os.path.join("./img/resume/%s.tex" % resume_type)
    if not os.path.isfile(resume_content_tex_fn):
        print("Resume contents for type %s not found.Skipping build" %
              resume_type)
        exit()

    # parse and rewrite main tex file
    resume_main_tex_fn = os.path.abspath("./img/resume/main.tex")
    try:
        with open(resume_main_tex_fn, "r") as of:
            lines = of.readlines()
    except IOError:
        print("Resume main tex file not found. Skipping build")
        exit()

    lines[-1] = "\\input{%s.tex}\n" % resume_type
    with open(resume_main_tex_fn, "w") as of:
        of.write("".join(lines))

    # change over to the resume dir and run latex
    curr_dir = os.getcwd()
    resume_dir = os.path.abspath("./img/resume")
    cmd_str = """
cd %s
pdflatex %s
cd %s
    """ % (resume_dir, resume_main_tex_fn, curr_dir)
    os.system(cmd_str)

    # delete extra files if any
    extra_fn_types = ["aux", "log", "out", "synctex.gz"]
    for root, dirs, files in os.walk(os.path.abspath("./img/resume")):
        for fn in files:
            if any([fn.endswith(ext) for ext in extra_fn_types]):
                fn_fullname = os.path.join(os.path.abspath("./img/resume"), fn)
                os.remove(fn_fullname)


def _build_site(refresh=False):
    """
    Runs jekyll to build the website.

    :param refresh: (bool) True to remove the _site folder before building
    """

    site_dir = os.path.abspath("_site")
    if refresh:
        os.system("rm -rf %s" % site_dir)

    cmd_str = "jekyll build"
    os.system(cmd_str)


def _sync(commit_msg=None):
    """
    Git sync the website.
    Should be run only after it has been built with jekyll.

    :param commit_msg: (str) Message for using as a commit message
                       during git push
    """

    if commit_msg is None:
        commit_msg = "Autogenerated commit msg # %d" % random.randint(0, 10000)

    cmd_str = """
git add *
git commit -m %s
git push -u origin master
    """ % commit_msg

    os.system(cmd_str)


# MAIN

# user arguments
parser = argparse.ArgumentParser("Tanmoy's personal website builder")
parser.add_argument("-cv", "--resume_type", default="short",
                    help="Resume type to build")
parser.add_argument("-m", "--commit_msg",
                    help="Commit message to use for git push")
parser.add_argument("-r", "--refresh", action="store_true",
                    help="Raise this to remove the _site folder and rebuild")

# parse user arguments
args = parser.parse_args()

# build resume
print("Building resume...")
_build_resume(resume_type=args.resume_type)

# build the site
print("Building site...")
_build_site(refresh=args.refresh)

# sync to github
print("Syncing to github...")
_sync(commit_msg=args.commit_msg)
